type executionCleanupAttemptProcessKillerFunc func(int) error

func (f executionCleanupAttemptProcessKillerFunc) KillGroup(pgid int) error {
	if f == nil {
		return nil
	}
	return f(pgid)
}

type executionCleanupAttemptProcess struct {
	PID       int
