type providerChildRunner struct {
	bin     string
	started chan int
	mode    string
}

func newProviderChildRunner(t *testing.T, dir, provider, mode string) *providerChildRunner {
	t.Helper()
	sleepPath, err := exec.LookPath("sleep")
	if err != nil {
		t.Skipf("sleep not available: %v", err)
	}
	bin := filepath.Join(dir, provider)
	if err := os.Symlink(sleepPath, bin); err != nil {
		t.Fatalf("symlink fake %s: %v", provider, err)
	}
	return &providerChildRunner{bin: bin, started: make(chan int, 1), mode: mode}
}

func (r *providerChildRunner) Run(opts RunArgs) (*Result, error) {
	cmd := exec.Command(r.bin, "120")
	cmd.SysProcAttr = &syscall.SysProcAttr{Setpgid: true}
	if err := cmd.Start(); err != nil {
		return &Result{ExitCode: 1, Error: err.Error()}, nil
	}
	pid := cmd.Process.Pid
	go func() { _, _ = cmd.Process.Wait() }()
	r.started <- pid
	switch r.mode {
	case "interrupt":
		ctx := opts.Context
		if ctx == nil {
			ctx = context.Background()
		}
		<-ctx.Done()
		return &Result{ExitCode: 1, Error: ctx.Err().Error()}, nil
	case "failure":
		return &Result{ExitCode: 1, Error: "synthetic failure"}, nil
	default:
		return &Result{ExitCode: 0}, nil
	}
}

func waitForProviderChildren(t *testing.T, rootPID int, pids ...int) {
	t.Helper()
	deadline := time.Now().Add(3 * time.Second)
	for time.Now().Before(deadline) {
		procs, err := providerChildScanner(context.Background(), rootPID, time.Now().UTC())
		if err == nil {
			seen := map[int]bool{}
			for _, p := range procs {
				seen[p.PID] = true
			}
			all := true
			for _, pid := range pids {
				if !seen[pid] {
					all = false
					break
				}

		for _, proc := range candidates {
			if signalProcessAlive(proc.PID) {
				allGone = false
				break
			}
		}
		if allGone {
			return
		}
		time.Sleep(25 * time.Millisecond)
	}
	for _, proc := range candidates {
		if !signalProcessAlive(proc.PID) {
			continue
		}
		if err := syscall.Kill(proc.PID, syscall.SIGKILL); err != nil && err != syscall.ESRCH {
			report.KillErrors = append(report.KillErrors, fmt.Sprintf("SIGKILL pid %d: %v", proc.PID, err))
		}
	}
}

func signalProcessAlive(pid int) bool {
	if pid <= 0 {
		return false
	}
	return syscall.Kill(pid, 0) == nil
}

func scanAttemptProcesses(ctx context.Context) ([]attemptProcessInfo, error) {
	cmd := exec.CommandContext(ctx, "ps", "-axo", "pid=,ppid=,pgid=,command=")
	out, err := cmd.Output()
	if err != nil {
		return nil, err
	}
	processes := parseAttemptPS(out)
	for i := range processes {
		processes[i].Cwd = readProcessCwd(processes[i].PID)
	}
	return processes, nil
}

func parseAttemptPS(out []byte) []attemptProcessInfo {
	lines := bytes.Split(out, []byte{'\n'})
	processes := make([]attemptProcessInfo, 0, len(lines))
	for _, line := range lines {
		fields := strings.Fields(string(line))
		if len(fields) < 3 {
			continue
		}
		pid, pidErr := strconv.Atoi(fields[0])
		ppid, ppidErr := strconv.Atoi(fields[1])
		pgid, pgidErr := strconv.Atoi(fields[2])
		if pidErr != nil || ppidErr != nil || pgidErr != nil {
			continue
		}
		cmdline := ""
		if len(fields) > 3 {
			cmdline = strings.Join(fields[3:], " ")
		}
		processes = append(processes, attemptProcessInfo{
			PID:     pid,
			PPID:    ppid,
			PGID:    pgid,
			Command: cmdline,
		})
	}
	return processes
}

func readProcessCwd(pid int) string {
	if pid <= 0 {
		return ""
	}
	if cwd, err := os.Readlink(filepath.Join("/proc", strconv.Itoa(pid), "cwd")); err == nil {
		return cwd
	}
	return ""
}

