	Effort        string
	Timeout       time.Duration // idle (inactivity) timeout; nonzero overrides Config.TimeoutMS
	WallClock     time.Duration // absolute wall-clock cap; nonzero overrides Config.WallClockMS
	WorkDir       string
	Permissions   string // permission level override: safe, supervised, unrestricted
	SessionLogDir string // per-run override for session log dir; used by execute-bead to redirect embedded-agent runtime state out of the worktree root
	Role          string
	CorrelationID string
	Env           map[string]string
}

// AgentRunRuntime is the SD-024 successor to RunArgs for the agent
// run path. Durable knobs (Harness, Model, Provider, Effort,
// Permissions, Timeout, WallClock, SessionLogDir) are stripped — they
// live on config.ResolvedConfig and are passed via RunWithConfig's
// rcfg argument. Only non-serializable plumbing and per-invocation
// runtime intent remain.
//
// See SD-024 / TD-024 §Runtime structs and §Stage 2 bead 17.
type AgentRunRuntime struct {
	Prompt                string
	PromptFile            string
	PromptSource          string
	Output                io.Writer // optional live service-event progress sink
	WorkLogPhase          string    // optional phase label for live service-event progress
	Correlation           map[string]string
	Record                bool
	Replay                bool
	WorkDir               string
	EstimatedPromptTokens int
	RequiresTools         bool
	SessionLogDirOverride string
	// HarnessOverride, ProviderOverride, ModelOverride, ProfileOverride, and
	// PermissionsOverride let a caller override one durable knob from rcfg for
	// this single invocation without re-resolving the full ResolvedConfig.
	// SD-024 step B22d-d: execute-bead sets permissions=unrestricted; hidden
	// lifecycle calls use profile-only routing hints sourced from fizeau.
	HarnessOverride     string
	ProviderOverride    string
	ModelOverride       string
	ProfileOverride     string
	PermissionsOverride string
	// ClearRoutingPins drops rcfg Harness/Provider/Model passthrough for
	// hidden DDx lifecycle calls. Explicit runtime overrides still win.
	ClearRoutingPins bool
	Role             string
	CorrelationID    string
	Env              map[string]string
	// MinPowerOverride, when > 0, overrides rcfg.MinPower() for this single
	// invocation. Used by the post-merge reviewer to pin MinPower above the
	// implementer's actual selected power, biasing routing toward a stronger
	// reviewer model (R4 pairing: reviewer >= impl + 1 power).
	MinPowerOverride int
	// ClearMinPower drops rcfg.MinPower() for this single invocation. Auxiliary
	// lifecycle classifier calls should not inherit implementation power bounds;
	// Fizeau owns routing for those hidden dispatches.
	ClearMinPower bool
	// ClearMaxPower drops rcfg.MaxPower() for this single invocation. This is
