	return publishCloneResult(ctx, ws, res)
}

func (LocalCloneAttemptBackend) Cleanup(_ context.Context, ws *AttemptWorkspace) error {
	if ws == nil || ws.WorkDir == "" {
		return nil
	}
	if ws.KeepOnError {
		return nil
	}
	return os.RemoveAll(ws.WorkDir)
}

